import React from "react";

export default function Login(props) {
  return (
    <div className="main">
      {props.login && (
        <div className="card">
          <h2
            style={{
              marginLeft: "-2rem",
              padding: "2rem",
              borderLeft: "5px solid #673fd7",
              color: "#673fd7"
            }}
          >
            Login
          </h2>
          <p style={{ color: "red" }}>
            {props.status === "" ? <br /> : props.status}
          </p>
          <input
            id="username"
            value={props.username}
            onChange={props.handleNameChange}
            className="input"
            autoComplete="off"
            placeholder="Username"
          ></input>
          <br></br>
          <br></br>

          <input
            id="passwd"
            type={props.isHidden ? "password" : "text"}
            value={props.passwd}
            onChange={props.handlePasswdChange}
            className="input"
            autoComplete="off"
            placeholder="Password"
          ></input>
          {!props.isHidden && (
            <img
              src="data:image/png;base64,"
              alt="unhide"
              onClick={props.handleHidden}
              style={{
                cursor: "pointer",
                width: "1rem",
                position: "relative",
                marginLeft: "-1.5rem"
              }}
            />
          )}
          {props.isHidden && (
            <img
              src="data:image/png;base64,"
              alt="hide"
              onClick={props.handleHidden}
              style={{
                cursor: "pointer",
                width: "1rem",
                position: "relative",
                marginLeft: "-1.5rem"
              }}
            />
          )}
          <br></br>
          <br></br>
          <div className="options">
            <button
              onClick={props.submitLogin}
              className={!props.loading ? "button1" : "button1--loading"}
            >
              Log in
            </button>
            <br></br>
            <br></br>
            <h2 style={{ color: "#673fd7" }}>OR</h2>
            <br></br>

            <button onClick={props.handleLoginChange} className="button1">
              Sign up
            </button>
          </div>
        </div>
      )}
      {!props.login && (
        <div class="main">
          <div className="card">
            <h2
              style={{
                marginLeft: "-2rem",
                padding: "2rem",
                borderLeft: "5px solid #673fd7",
                color: "#673fd7"
              }}
            >
              Sign Up
            </h2>
            <p style={{ color: "red" }}>
              {props.status === "" ? <br></br> : props.status}
            </p>
            <input
              id="username"
              value={props.username}
              className="input"
              onChange={props.handleNameChange}
              autoComplete="off"
              placeholder="Username"
            ></input>
            <br></br>
            <br></br>

            <input
              id="passwd"
              type={props.isHidden ? "password" : "text"}
              value={props.passwd}
              onChange={props.handlePasswdChange}
              className="input"
              autoComplete="off"
              placeholder="Password"
            ></input>
            {!props.isHidden && (
              <img
                src="data:image/png;base64,"
                alt="unhide"
                onClick={props.handleHidden}
                style={{
                  cursor: "pointer",
                  width: "1rem",
                  position: "relative",
                  marginLeft: "-1.5rem"
                }}
              />
            )}
            {props.isHidden && (
              <img
                src="data:image/png;base64,"
                alt="hide"
                onClick={props.handleHidden}
                style={{
                  cursor: "pointer",
                  width: "1rem",
                  position: "relative",
                  marginLeft: "-1.5rem"
                }}
              />
            )}
            <br></br>
            <br></br>
            <div class="options">
              <button
                onClick={props.submitSignup}
                className={!props.loading ? "button1" : "button1--loading"}
              >
                Sign Up
              </button>
              <br></br>
              <h2 style={{ color: "#673fd7" }}>OR</h2>
              <button onClick={props.handleLoginChange} className="button1">
                Log in
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
